import { getFeeStructure, type FeeStructure } from '@/lib/data/seller-payouts'

export function FeeCalculator() {
  const [saleAmount, setSaleAmount] = useState('10.00')
  const [fees, setFees] = useState<FeeStructure | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    loadFees()
  }, [])

  const loadFees = async (amount?: number) => {
    try {
      setLoading(true)
      const amountInCents = amount ?? Math.round(parseFloat(saleAmount) * 100)
      const result = await getFeeStructure(
        isNaN(amountInCents) ? undefined : amountInCents
      )
      if (result) {
        setFees(result)
      }
    } catch {
      // Silently fail — show cached data
    } finally {
      setLoading(false)
    }
  }

  const handleAmountChange = (value: string) => {
    setSaleAmount(value)
    const parsed = parseFloat(value)
    if (!isNaN(parsed) && parsed > 0) {
      loadFees(Math.round(parsed * 100))
    }
  }

  return (
    <div className="bg-card rounded-lg border border-border p-5">
      <h3 className="text-sm font-semibold text-primary mb-4">
        Fee Calculator
      </h3>

      {/* Fee rates */}
      {fees && (
        <div className="space-y-2 mb-5">
          <div className="flex items-center justify-between text-sm">
            <span className="text-secondary">
              {fees.platform_commission.description}
            </span>
            <span className="font-medium text-primary">
              {fees.platform_commission.display}
            </span>
          </div>
          <div className="flex items-center justify-between text-sm">
            <span className="text-secondary">
              {fees.stripe_processing.description}
            </span>
            <span className="font-medium text-primary">
              {fees.stripe_processing.display}
            </span>
          </div>
        </div>
      )}

      {/* Calculator */}
      <div className="border-t border-border pt-4">
        <label className="block text-xs font-medium text-secondary mb-2">
          Estimate your net earnings
        </label>
        <div className="flex items-center gap-3 mb-4">
          <span className="text-secondary text-sm">$</span>
          <input
            type="number"
            min="0.01"
            step="0.01"
            value={saleAmount}
            onChange={(e) => handleAmountChange(e.target.value)}
            className="flex-1 px-3 py-2 border border-border rounded-lg bg-background text-primary text-sm focus:outline-none focus:ring-2 focus:ring-action/50"
            placeholder="Enter sale price"
          />
        </div>

        {fees && !loading && (
          <div className="space-y-2 text-sm">
            <div className="flex justify-between">
              <span className="text-secondary">Sale amount</span>
              <span className="text-primary">
                {formatAmount(fees.example.sale_amount / 100, 'USD')}
              </span>
            </div>
            <div className="flex justify-between">
              <span className="text-secondary">Platform fee (10%)</span>
              <span className="text-negative">
                -{formatAmount(fees.example.platform_fee / 100, 'USD')}
              </span>
            </div>
            <div className="flex justify-between">
              <span className="text-secondary">Stripe processing</span>
              <span className="text-negative">
                -{formatAmount(fees.example.stripe_fee / 100, 'USD')}
              </span>
            </div>
            <div className="flex justify-between pt-2 border-t border-border">
              <span className="font-medium text-primary">You receive</span>
              <span className="font-bold text-positive">
                {formatAmount(fees.example.net_amount / 100, 'USD')}
              </span>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

